INSERT INTO "portfolios" ("slug", "featured", "title", "companyBuiltWith", "desc", "projectColor", "projectText", "outcome", "link", "moreInfoLink", "projectLogo", "image", "status", "skills", "order") VALUES ('cardo', true, 'Cardo', 'Carthagos', 'Cardo is a knowledge-sharing platform designed to bridge mentorship gaps in the labor market by connecting professionals with consultants from top American firms. Built as part of the Carthagos team, I led the frontend development of the platform using React, JavaScript. I implemented key features such as landing pages, dashboards, LinkedIn-based authentication, user onboarding, scheduling via Calendly, Jotform integrations, and a real-time chat system using Socket.IO. I worked closely with the backend team to integrate REST APIs, ensuring a seamless and responsive user experience.', '#5555DB', '#ffffff', 'The platform successfully launched and connected professionals to expert mentors in real-time. It was praised for its intuitive UI, fast performance, and real-time chat experience. My frontend contributions enabled efficient scheduling and interaction between users and mentors, contributing to the platform''s adoption and growth.', 'http://www.hellocardo.org/', 'https://www.carthagos.com/projects/Cardo', 'portfolio/cardo/logo.svg', 'portfolio/cardo/cover.png', 'live', ARRAY['HTML/CSS', 'JavaScript', 'React.js', 'Redux', 'Web Sockets', 'Calendly', 'Express.js', 'Node.js', 'MongoDB', 'Git']::TEXT[], 0);
