INSERT INTO "work_experience" ("duration", "designation", "company", "location", "icon", "companyDescription", "whatIdid", "skillsUsed", "achievement", "companySite", "order") VALUES ('Jan 2023 - Present', 'Frontend Developer', 'Icecode Software', 'Dubai, UAE', NULL, 'Icecode is a software company that specializes in building all things Software from Apps, ERP''s, CRM''s, to little microservices. As a Frontend Developer, I evaluate project requirements and leverage diverse technical skill sets to develop web applications, designs, and dashboards.', '[{"title":"Frontend Architecture","desc":"Built and optimized scalable dashboards using React 18 and Next.js with modular components and maintainable architecture."},{"title":"API Integration Framework","desc":"Designed and implemented an SDK with GraphQL-Codegen and Apollo Client to standardize API integration."},{"title":"Team Leadership & Code Quality","desc":"Conducted PR reviews, mentored developers, and introduced best practices for React state management and architecture."},{"title":"Testing & Quality Assurance","desc":"Implemented testing standards with Jest and React Testing Library, including snapshot testing for UI reliability."},{"title":"CMS Development","desc":"Developed a React-based CMS with real-time preview to simplify content publishing workflows."}]'::jsonb, ARRAY['React', 'TypeScript', 'Next.js', 'Redux', 'React Context API', 'GraphQL', 'Apollo Client', 'React Query', 'Tailwind CSS', 'JavaScript', 'jQuery', 'MySQL', 'Jest', 'RTL', 'Docker', 'Azure DevOps', 'CI/CD Pipelines', 'Wordpress']::TEXT[], NULL, 'http://carthagos.com', 0);
INSERT INTO "work_experience" ("duration", "designation", "company", "location", "icon", "companyDescription", "whatIdid", "skillsUsed", "achievement", "companySite", "order") VALUES ('June 2020 - Mar 2022', 'Fullstack Developer', 'Carthagos', 'Remote', NULL, 'Carthagos is a global product studio focused on helping start-ups create brands and technologies. The Full Stack Developer evaluates project requirements and maximizes diverse technical skills to develop web applications, designs, and dashboards.', '[{"title":"Data Visualization & Dashboards","desc":"Delivered analytics dashboards with Next.js SSR, React hooks, and reusable UI components."},{"title":"API & Real-Time Integration","desc":"Built GraphQL and REST integrations and added WebSocket support for real-time data updates."},{"title":"Performance Optimization","desc":"Applied React performance optimization techniques, including lazy loading, code-splitting, and caching."},{"title":"UI Development & Accessibility","desc":"Converted Figma designs into responsive React UIs with accessibility and cross-browser support."},{"title":"Mentorship & Best Practices","desc":"Mentored junior developers in React state management and testing practices."}]'::jsonb, ARRAY['React', 'TypeScript', 'Next.js', 'Redux', 'React Context API', 'Tailwind CSS', 'jQuery', 'REST APIs', 'Express.js', 'Node.js', 'MongoDB', 'MySQL', 'Wordpress']::TEXT[], NULL, 'http://carthagos.com', 1);
INSERT INTO "work_experience" ("duration", "designation", "company", "location", "icon", "companyDescription", "whatIdid", "skillsUsed", "achievement", "companySite", "order") VALUES ('Jun 2017 - Present', 'Freelancer', 'Upwork', NULL, NULL, 'Upwork is platfrom for Freelancers', '[{"title":"Service Delivery","desc":"Exhibit strong project management skills and knowledge of technical processes in completing a wide array of projects & milestones, including fixing bugs, mentoring developers, and developing websites and software."},{"title":"Client Relations","desc":"Nurture collaborative relations with clients while maintaining consistent contact to gather and define requirements, develop specifications for project plans, and provide visibility and updates on project progress."},{"title":"Project Management","desc":"Proficiently manage projects, from proposal to completion, leveraging out-of-the-box thinking in solving complex problems and innovating strategic initiatives to achieve client expectations."}]'::jsonb, ARRAY['HTML/CSS/JS', 'ReactJS', 'Wordpress', 'React Native', 'PHP', 'Express']::TEXT[], 'Maintained a +90% job success rate and acquired a top-rated developer badge by consistently delivering quality project output.', '', 2);
INSERT INTO "work_experience" ("duration", "designation", "company", "location", "icon", "companyDescription", "whatIdid", "skillsUsed", "achievement", "companySite", "order") VALUES ('Feb 2018 - Nov 2019', 'Fullstack Developer', 'HSNA Technologies', 'Karachi, Pakistan', NULL, 'HSNA is an IT company that works as a freelance organization, on various projects in view to client''s requirements.', '[{"title":"Web, Applications, and Systems Development","desc":"Maximized knowledge of basic web technologies, including HTML, CSS, Javascript, Bootstrap, jQuery, AJAX, PHP, MySQL, PHPmyAdmin, and WordPress, in developing systems based on client requirements."},{"title":"Team Collaboration","desc":"Communicated with cross-functional teams to identify issues & implement long-term technical solutions."},{"title":"Technical Management","desc":"Applied diverse skillset, impeccable analytical nature, and a capacity to identify, evaluate, and understand the project’s needs and provide an immediate response to technical challenges."}]'::jsonb, ARRAY['HTML/CSS/JS', 'Bootstrap', 'Wordpress', 'PHP', 'MySQL']::TEXT[], 'Demonstrated technical leadership and methodical advice in establishing optimized processes to efficiently direct and implement CRUD, CRM, and CMS applications.', 'https://www.hsnatech.com', 3);
